def _settings_path() -> str:
    return os.path.join(os.path.dirname(os.path.abspath(__file__)), SETTINGS_FILE)


def _load_settings(path: str) -> dict[str, object]:
    try:
        with open(path, "r", encoding="utf-8") as f:
            obj = json.load(f)
        return obj if isinstance(obj, dict) else {}
    except (OSError, json.JSONDecodeError, UnicodeDecodeError):
        return {}


def _save_settings(path: str, data: dict[str, object]) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2, ensure_ascii=False)


def _as_bool(value: object, default: bool = False) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        v = value.strip().lower()
        if v in {"1", "true", "yes", "on"}:
            return True
        if v in {"0", "false", "no", "off", ""}:
            return False
    if value is None:
        return default
    return bool(value)


def _register_proc(proc: subprocess.Popen) -> None:
    with _ACTIVE_PROCS_LOCK:
        _ACTIVE_PROCS.add(proc)


def _unregister_proc(proc: subprocess.Popen) -> None:
    with _ACTIVE_PROCS_LOCK:
        _ACTIVE_PROCS.discard(proc)


def _terminate_active_processes() -> None:
    with _ACTIVE_PROCS_LOCK:
        procs = list(_ACTIVE_PROCS)
    for proc in procs:
        try:
            if proc.poll() is None:
                proc.terminate()
                try:
                    proc.wait(timeout=1.5)
                except subprocess.TimeoutExpired:
                    proc.kill()
        except Exception:
            pass


def _ui_alive(root: tk.Misc) -> bool:
    if _APP_SHUTTING_DOWN.is_set():
        return False
    try:
        return bool(root.winfo_exists())
    except tk.TclError:
        return False


def _safe_after(root: tk.Misc, delay_ms: int, callback: Callable[[], None]) -> None:
    if not _ui_alive(root):
        return
    try:
        root.after(delay_ms, callback)
    except tk.TclError:
        pass


def _set_preferred_mono_font(name: str) -> None:
    global _PREFERRED_MONO_FONT
    _PREFERRED_MONO_FONT = name.strip() or None


def _register_private_font_windows(font_path: str) -> bool:
    """Register font privately for the current process (Windows only)."""
    try:
        import ctypes

        FR_PRIVATE = 0x10
        added = ctypes.windll.gdi32.AddFontResourceExW(font_path, FR_PRIVATE, 0)
        return bool(added)
    except Exception:
        return False


def _font_cache_dir() -> str:
    p = os.path.join(tempfile.gettempdir(), "flashgui-font-cache")
    os.makedirs(p, exist_ok=True)
    return p


def _download_font(font_name: str) -> str | None:
    info = _FONT_DOWNLOADS.get(font_name)
    if not info:
        return None
    url, filename = info
    dst = os.path.join(_font_cache_dir(), filename)
    if os.path.isfile(dst) and os.path.getsize(dst) > 0:
        return dst

    candidates: list[str] = [url]
    if "github.com/" in url and "/raw/refs/heads/master/" in url:
        # Fallbacks in case upstream branch/path handling changes
        raw = (
            url.replace("https://github.com/", "https://raw.githubusercontent.com/")
            .replace("/raw/refs/heads/master/", "/HEAD/")
        )
        candidates.extend(
            [
                raw,
                raw.replace("/HEAD/", "/main/"),
                raw.replace("/HEAD/", "/master/"),
            ]
        )

    # Deduplicate while preserving order
    seen: set[str] = set()
    unique_candidates: list[str] = []
    for c in candidates:
        if c not in seen:
            seen.add(c)
            unique_candidates.append(c)

    last_error: Exception | None = None
    for candidate in unique_candidates:
        try:
            req = urllib.request.Request(candidate, headers={"User-Agent": "flashgui/1.0"})
            with urllib.request.urlopen(req, timeout=30) as resp, open(dst, "wb") as out:
                shutil.copyfileobj(resp, out)
            if os.path.isfile(dst) and os.path.getsize(dst) > 0:
                return dst
        except Exception as exc:
            last_error = exc
            try:
                if os.path.isfile(dst):
                    os.remove(dst)
            except OSError:
                pass

    if last_error is not None:
        raise RuntimeError(f"Failed to download font '{font_name}' from all known URLs: {last_error}")
    return None


def _ensure_font_available(font_name: str, logger: Callable[[str], None] | None = None) -> bool:
    if not font_name:
        return False
    if font_name in _tkfont.families():
        return True
    if sys.platform.startswith("win"):
        try:
            path = _download_font(font_name)
            if not path:
                if logger:
                    logger(f"Font '{font_name}' is not installed and no download source is configured.")
                return False
            if _register_private_font_windows(path):
                if path not in _DOWNLOADED_FONT_PATHS:
                    _DOWNLOADED_FONT_PATHS.append(path)
                return True
            if logger:
                logger(f"Downloaded '{font_name}' but failed to register the font.")
            return False
        except Exception as exc:
            if logger:
                logger(f"Failed to download/register '{font_name}': {exc}")
            return False
    if logger:
        logger(
            f"Font '{font_name}' is not installed. Auto-download is currently supported on Windows only."
        )
    return False


def _install_embedded_font() -> None:
    """Decode/register embedded TTF payload when present."""
    global _EMBEDDED_FONT_PATH

    if not _EMBEDDED_TTF_B64.strip() or _EMBEDDED_FONT_PATH:
        return

    try:
        raw = base64.b64decode(_EMBEDDED_TTF_B64, validate=True)
        fd, path = tempfile.mkstemp(prefix="flashgui_font_", suffix=".ttf")
        with os.fdopen(fd, "wb") as f:
            f.write(raw)
        _EMBEDDED_FONT_PATH = path

        if sys.platform.startswith("win"):
            _register_private_font_windows(path)

        def _cleanup() -> None:
            p = _EMBEDDED_FONT_PATH
            if not p:
                return
            try:
                if sys.platform.startswith("win"):
                    import ctypes

                    FR_PRIVATE = 0x10
                    ctypes.windll.gdi32.RemoveFontResourceExW(p, FR_PRIVATE, 0)
            except Exception:
                pass
            try:
                os.remove(p)
            except OSError:
                pass

        atexit.register(_cleanup)
    except (binascii.Error, OSError, ValueError):
        _EMBEDDED_FONT_PATH = None


def _cleanup_downloaded_fonts() -> None:
    if not sys.platform.startswith("win"):
        return
    try:
        import ctypes

        FR_PRIVATE = 0x10
        for p in _DOWNLOADED_FONT_PATHS:
            try:
                ctypes.windll.gdi32.RemoveFontResourceExW(p, FR_PRIVATE, 0)
            except Exception:
                pass
    except Exception:
        pass


atexit.register(_cleanup_downloaded_fonts)


def _pick_mono(size: int = 10) -> tuple[str, int]:
    """Return the best available monospace font tuple."""
    for name in (
        _PREFERRED_MONO_FONT,
        _EMBEDDED_FONT_NAME_HINT,
        "Consolas",
        "Lucida Console",
        "Courier New",
        "Courier",
    ):
        if name and name in _tkfont.families():
            return (name, size)
    return ("Courier", size)


