def _resolve_theme_name(style: ttk.Style, requested: str) -> str:
    """Resolve user-selected theme to an actually available Tk theme name."""
    req = (requested or "").strip()
    if not req:
        return ""
    available = set(style.theme_names())
    if req in available:
        return req
    mapped = _THEME_ALIASES.get(req.lower(), "")
    if mapped and mapped in available:
        return mapped
    return ""


def _theme_is_dark(theme_name: str) -> bool:
    n = (theme_name or "").strip().lower()
    if n in _CUSTOM_DARK_THEMES:
        return True
    if n in {"darkly", "cyborg", "superhero", "vapor", "solar"}:
        return True
    return any(k in n for k in ("dark", "black", "night", "midnight", "graphite", "macosx-dark"))

