# ────────────────────────── tool discovery ─────────────────────────────────────

def _resolve_binary(name: str, env_var: str) -> str:
    override = os.getenv(env_var, "").strip()
    if override:
        return override
    found = shutil.which(name)
    return found if found else name


def _get_version(binary: str) -> str | None:
    try:
        proc = subprocess.run(
            [binary, "--version"], check=False, capture_output=True, text=True, errors="replace", timeout=8
        )
        lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).strip().splitlines()
        return lines[0] if lines else None
    except Exception:
        return None


def _list_programmers(binary: str) -> list[str]:
    try:
        proc = subprocess.run([binary], check=False, capture_output=True, text=True, errors="replace", timeout=12)
        lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines()
        start = -1
        for idx, line in enumerate(lines):
            if "Valid choices are:" in line:
                start = idx + 1
                break
        if start == -1:
            return []
        programmers: list[str] = []
        seen: set[str] = set()
        for line in lines[start:]:
            clean = line.strip().replace(",", "").replace(".", "")
            if not clean:
                continue
            if clean.startswith("Please"):
                break
            for token in clean.split():
                if token and token[0].isalpha() and token.lower() not in {"and", "or"}:
                    if token not in seen:
                        programmers.append(token)
                        seen.add(token)
        return programmers
    except Exception:
        return []


def _is_minipro_tool(tool: str, binary: str = "") -> bool:
    t = (tool or "").strip().lower()
    if t == "minipro":
        return True
    b = os.path.basename((binary or "").strip()).lower()
    return b in {"minipro", "minipro.exe"}


def _detect_minipro_hardware(minipro_binary: str) -> tuple[bool, str, list[str]]:
    """Probe minipro programmer with non-invasive calls.

    Returns (detected, label, relevant_output_lines).
    """

    def _run_probe(args: list[str]) -> tuple[list[str], str]:
        try:
            proc = subprocess.run(
                [minipro_binary, *args],
                check=False,
                capture_output=True,
                text=True,
                errors="replace",
                timeout=120,
            )
        except Exception:
            return [], ""

        out = ((proc.stdout or "") + "\n" + (proc.stderr or "")).strip()
        raw_lines = [ln.rstrip("\r\n") for ln in out.splitlines() if ln.strip()]
        found_line = ""
        for ln in raw_lines:
            if ln.lower().startswith("found "):
                found_line = ln.strip()
                break
        diag_prefixes = (
            "found ",
            "warning:",
            "expected",
            "device code:",
            "serial code:",
            "manufactured:",
            "usb speed:",
            "supply voltage:",
        )
        lines = [ln for ln in raw_lines if ln.lower().startswith(diag_prefixes)]
        if not lines:
            lines = raw_lines[:20]
        return lines, found_line

    lines, found_line = _run_probe(["-V"])
    if not found_line:
        fallback_lines, found_line = _run_probe(["-l"])
        if fallback_lines:
            lines = fallback_lines

    if not found_line:
        return False, "", lines
    return True, found_line, lines


def _list_minipro_devices(minipro_binary: str, limit: int = 8192) -> list[str]:
    """Return minipro part names from `minipro -l` output."""
    try:
        proc = subprocess.run(
            [minipro_binary, "-l"],
            check=False,
            capture_output=True,
            text=True,
            errors="replace",
            timeout=120,
        )
    except Exception:
        return []

    lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines()
    parts: list[str] = []
    seen: set[str] = set()
    skip_prefixes = (
        "minipro version",
        "usage:",
        "see the manual",
        "found ",
        "warning:",
        "device code:",
        "serial code:",
        "manufactured:",
        "usb speed:",
        "supply voltage:",
    )

    for raw in lines:
        s = (raw or "").strip()
        if not s:
            continue
        if s.lower().startswith(skip_prefixes):
            continue
        token = s.split()[0].strip()
        if not token:
            continue
        if not re.fullmatch(r"[A-Za-z0-9@._()+\-/]+", token):
            continue
        k = token.lower()
        if k in seen:
            continue
        seen.add(k)
        parts.append(token)
        if len(parts) >= limit:
            break
    return parts


def _autodetect_minipro_spi_devices(minipro_binary: str) -> tuple[bool, str, list[str], list[str], str]:
    """Autodetect SPI devices using minipro -a (8/16-bit buses).

    Returns (detected_programmer, label, chips, lines, bus_width).
    """
    all_lines: list[str] = []
    found_line = ""

    def _collect_candidates(lines: list[str]) -> list[str]:
        chips: list[str] = []
        seen: set[str] = set()
        for raw in lines:
            s = (raw or "").strip()
            if not s:
                continue
            lo = s.lower()
            if (
                lo.startswith("found ")
                or lo.startswith("warning:")
                or lo.startswith("expected")
                or lo.startswith("device code:")
                or lo.startswith("serial code:")
                or lo.startswith("manufactured:")
                or lo.startswith("usb speed:")
                or lo.startswith("supply voltage:")
                or lo.startswith("autodetecting device")
                or lo.endswith("device(s) found.")
            ):
                continue
            if not re.fullmatch(r"[A-Za-z0-9@._()+\-/]+", s):
                continue
            k = s.lower()
            if k in seen:
                continue
            seen.add(k)
            chips.append(s)
        return chips

    for width in ("8", "16"):
        try:
            proc = subprocess.run(
                [minipro_binary, "-a", width],
                check=False,
                capture_output=True,
                text=True,
                errors="replace",
                timeout=60,
            )
        except Exception:
            continue

        raw_lines = [ln.rstrip("\r\n") for ln in ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines() if ln.strip()]
        all_lines.extend(raw_lines)

        if not found_line:
            for ln in raw_lines:
                if ln.lower().startswith("found "):
                    found_line = ln.strip()
                    break

        chips = _collect_candidates(raw_lines)
        if chips:
            return bool(found_line), found_line, chips, raw_lines[:120], width

    supported = _list_minipro_devices(minipro_binary)
    if supported:
        all_lines.append("No live SPI chip match from minipro -a 8/-a 16; listing supported minipro parts instead.")
        return bool(found_line), found_line, supported, all_lines[:120], ""

    return bool(found_line), found_line, [], all_lines[:120], ""


def _extract_chip_id_from_lines(lines: list[str]) -> str:
    found_ids: list[str] = []
    seen: set[str] = set()

    for raw in lines:
        s = (raw or "").strip()
        if not s:
            continue

        m_chip = re.search(r"\bchip\s*id\s*:\s*(0x[0-9a-fA-F]+)", s, re.IGNORECASE)
        if m_chip:
            chip_id = m_chip.group(1).upper()
            if chip_id not in seen:
                seen.add(chip_id)
                found_ids.append(chip_id)

        patterns = (
            r"compare_id:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
            r"(?:probe_spi_rdid|spi_rdid)\s*:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
            r"\bid1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
        )
        for pat in patterns:
            m_id = re.search(pat, s, re.IGNORECASE)
            if not m_id:
                continue
            try:
                chip_id = f"0x{int(m_id.group(1), 16):02X}{int(m_id.group(2), 16):X}"
            except ValueError:
                continue
            if chip_id not in seen:
                seen.add(chip_id)
                found_ids.append(chip_id)

    if not found_ids:
        return "N/A"
    return ", ".join(found_ids)


def _extract_probe_ids_from_lines(lines: list[str]) -> list[tuple[int, int]]:
    """Extract (manufacturer_id, model_id) pairs from probe output lines."""
    ids: list[tuple[int, int]] = []
    seen: set[tuple[int, int]] = set()
    patterns = (
        r"compare_id:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
        r"(?:probe_spi_rdid|spi_rdid)\s*:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
        r"\bid1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
    )
    for line in lines:
        for pat in patterns:
            m = re.search(pat, line, re.IGNORECASE)
            if not m:
                continue
            try:
                pair = (int(m.group(1), 16), int(m.group(2), 16))
            except ValueError:
                continue
            if pair in seen:
                continue
            seen.add(pair)
            ids.append(pair)
    return ids


def _resources_root() -> str:
    """Resolve resources directory with legacy-compatible fallbacks."""
    script_dir = os.path.dirname(os.path.abspath(__file__))
    candidates = (
        os.path.join(script_dir, "resources"),
        os.path.join(os.path.dirname(script_dir), "resources"),
        os.path.join(os.path.dirname(script_dir), "flashgui", "resources"),
    )
    for p in candidates:
        if os.path.isdir(p):
            return p
    return candidates[0]


def _normalize_chip_key(text: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", (text or "").lower())


def _probe_id_key(manuf: int, model: int) -> str:
    return f"{manuf:x}:{model:x}"


def _datasheet_search_targets(chip_name: str) -> list[str]:
    name = re.sub(r"\s+", " ", (chip_name or "").strip())
    if not name:
        return []
    return [f"https://www.alldatasheet.com/view.jsp?Searchword={quote_plus(name)}"]


def _find_local_datasheet_pdf(local_pdf_root: str, *names: str) -> str | None:
    if not os.path.isdir(local_pdf_root):
        return None

    try:
        entries = [n for n in os.listdir(local_pdf_root) if n.lower().endswith(".pdf")]
    except OSError:
        return None

    if not entries:
        return None

    by_lower_name: dict[str, str] = {}
    by_norm_stem: dict[str, str] = {}
    norm_entries: list[tuple[str, str]] = []

    for entry in entries:
        full = os.path.join(local_pdf_root, entry)
        lower = entry.lower()
        by_lower_name[lower] = full
        stem = os.path.splitext(entry)[0]
        norm = _normalize_chip_key(stem)
        if norm and norm not in by_norm_stem:
            by_norm_stem[norm] = full
        norm_entries.append((norm, full))

    for raw in names:
        if not raw:
            continue
        candidate = os.path.basename((raw or "").strip())
        if not candidate:
            continue

        direct = by_lower_name.get(candidate.lower())
        if direct:
            return direct

        if not candidate.lower().endswith(".pdf"):
            direct_pdf = by_lower_name.get((candidate + ".pdf").lower())
            if direct_pdf:
                return direct_pdf

        stem = os.path.splitext(candidate)[0]
        norm = _normalize_chip_key(stem)
        if not norm:
            continue

        norm_hit = by_norm_stem.get(norm)
        if norm_hit:
            return norm_hit

        for file_norm, full in norm_entries:
            if not file_norm:
                continue
            if norm in file_norm or file_norm in norm:
                return full

    return None


def _load_datasheet_hint_map() -> dict[str, dict[str, str]]:
    path = os.path.join(_resources_root(), "chips", "datasheet_hint_map.json")
    if not os.path.isfile(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            raw = json.load(f)
    except Exception:
        return {}
    if not isinstance(raw, dict):
        return {}

    out: dict[str, dict[str, str]] = {}
    for key, value in raw.items():
        if not isinstance(key, str) or not isinstance(value, dict):
            continue
        rec: dict[str, str] = {}
        for field in ("vendor", "preferred_name", "datasheet_url", "datasheet_pdf_url", "local_pdf"):
            v = value.get(field)
            if isinstance(v, str) and v.strip():
                rec[field] = v.strip()
        if rec:
            out[key.lower()] = rec
    return out


def _datasheet_candidate_names(
    chip: str,
    model: str,
    vendor: str,
    probe_ids: list[tuple[int, int]] | None = None,
) -> list[str]:
    ids = probe_ids or []
    hint_map = _load_datasheet_hint_map()
    out: list[str] = []
    seen: set[str] = set()

    def _add(name: str) -> None:
        n = (name or "").strip()
        if not n:
            return
        key = _normalize_chip_key(n)
        if not key or key in seen:
            return
        seen.add(key)
        out.append(n)

    _add(chip)
    _add(model)
    if vendor and model:
        _add(f"{vendor} {model}")

    for manuf, model_id in ids:
        hint = hint_map.get(_probe_id_key(manuf, model_id), {})
        if isinstance(hint, dict):
            _add(str(hint.get("preferred_name", "")))

    return out


def _resolve_datasheet_target(
    chip: str,
    model: str,
    vendor: str,
    probe_ids: list[tuple[int, int]] | None = None,
) -> tuple[str | None, list[str]]:
    ids = probe_ids or []
    hint_map = _load_datasheet_hint_map()
    local_pdf_root = os.path.join(_resources_root(), "datasheets")
    candidates = _datasheet_candidate_names(chip, model, vendor, ids)

    for manuf, model_id in ids:
        hint = hint_map.get(_probe_id_key(manuf, model_id), {})
        if not isinstance(hint, dict):
            continue

        local_pdf = str(hint.get("local_pdf", "")).strip()
        preferred = str(hint.get("preferred_name", "")).strip()
        local_hit = _find_local_datasheet_pdf(local_pdf_root, local_pdf, preferred, chip, model)
        if local_hit:
            return local_hit, candidates

        datasheet_pdf_url = str(hint.get("datasheet_pdf_url", "")).strip()
        if datasheet_pdf_url.lower().startswith(("http://", "https://")) and ".pdf" in datasheet_pdf_url.lower():
            return datasheet_pdf_url, candidates

        datasheet_url = str(hint.get("datasheet_url", "")).strip()
        if datasheet_url.lower().startswith(("http://", "https://")):
            return datasheet_url, candidates

    local_hit = _find_local_datasheet_pdf(local_pdf_root, *candidates)
    if local_hit:
        return local_hit, candidates

    search_name = candidates[0] if candidates else (chip or model)
    targets = _datasheet_search_targets(search_name)
    return (targets[0] if targets else None), candidates


def _open_datasheet_target(target: str) -> None:
    if not target:
        return
    if os.path.isfile(target):
        if sys.platform == "darwin":
            subprocess.Popen(["open", target])
            return
        if sys.platform.startswith("linux"):
            subprocess.Popen(["xdg-open", target])
            return
        startfile = getattr(os, "startfile", None)
        if callable(startfile):
            startfile(target)
            return
        webbrowser.open(f"file:///{target.replace(os.sep, '/')}")
        return
    webbrowser.open(target)


def _parse_minipro_device_info(lines: list[str], chip_fallback: str) -> tuple[str, str, str]:
    model = chip_fallback or "N/A"
    vendor = "N/A"
    size_str = "N/A"

    for raw in lines:
        s = (raw or "").strip()
        if not s:
            continue

        m_name = re.match(r"^Name:\s*(.+)$", s, re.IGNORECASE)
        if m_name:
            model = m_name.group(1).strip() or model

        m_mfr = re.match(r"^Manufacturer:\s*(.+)$", s, re.IGNORECASE)
        if m_mfr:
            vendor = m_mfr.group(1).strip() or vendor

        if size_str == "N/A":
            m_kb = re.search(r"\((\d+)\s*kB\)", s, re.IGNORECASE)
            if m_kb:
                size_str = f"{m_kb.group(1)} kB"
                continue
            m_mb = re.search(r"\((\d+)\s*MB\)", s, re.IGNORECASE)
            if m_mb:
                size_str = f"{m_mb.group(1)} MB"

    return model, vendor, size_str


