def _is_kde_desktop() -> bool:
    xdg = (os.environ.get("XDG_CURRENT_DESKTOP") or "").lower()
    sess = (os.environ.get("DESKTOP_SESSION") or "").lower()
    kde_flag = (os.environ.get("KDE_FULL_SESSION") or "").strip()
    return ("kde" in xdg) or ("plasma" in xdg) or ("kde" in sess) or (kde_flag not in {"", "0", "false", "False"})


def _preferred_keyring_manager_candidates() -> tuple[str, ...]:
    if _is_kde_desktop():
        return ("kwalletmanager5", "kwalletmanager", "seahorse")
    return ("seahorse", "kwalletmanager5", "kwalletmanager")


def _configured_udev_group() -> str:
    group = (os.environ.get("FLASHGUI_UDEV_GROUP") or "plugdev").strip()
    if not re.match(r"^[A-Za-z_][A-Za-z0-9_-]*$", group):
        return "plugdev"
    return group


def _apply_udev_group(rule_content: str) -> str:
    group = _configured_udev_group()
    return re.sub(r'GROUP="[^"]+"', f'GROUP="{group}"', rule_content)


def _udev_group_hint_text() -> str:
    group = _configured_udev_group()
    raw = (os.environ.get("FLASHGUI_UDEV_GROUP") or "").strip()
    if not raw:
        return f"Udev target group: {group} (default)"
    if group != raw:
        return f"Udev target group: {group} (invalid FLASHGUI_UDEV_GROUP={raw!r}; using default)"
    return f"Udev target group: {group} (from FLASHGUI_UDEV_GROUP)"


# Programmers that need a serial device path appended (programmer_arg → param key)
_SERIAL_PROGRAMMER_PARAMS: dict[str, str] = {
    "buspirate_spi": "dev",
    "serprog": "dev",
}


def _find_serial_port() -> str | None:
    """Return first ttyUSB/ttyACM device found under /dev, or None."""
    try:
        ports = sorted(
            f"/dev/{n}" for n in os.listdir("/dev")
            if n.startswith(("ttyUSB", "ttyACM"))
        )
        return ports[0] if ports else None
    except OSError:
        return None


def _detect_programmer_usb() -> list[tuple[str, str]]:
    """Scan lsusb for known flash programmers.

    Returns a list of (programmer_arg, description) tuples in discovery order.
    Duplicate programmer_args are suppressed (first match wins).
    """
    results: list[tuple[str, str]] = []
    seen: set[str] = set()

    try:
        proc = subprocess.run(
            ["lsusb"], check=False, capture_output=True, text=True, errors="replace", timeout=6
        )
        for line in (proc.stdout or "").splitlines():
            m = re.search(r"ID\s+([0-9a-fA-F]{4}):([0-9a-fA-F]{4})", line)
            if not m:
                continue
            vid, pid = m.group(1).lower(), m.group(2).lower()
            for (v, p, prog, label) in _USB_PROGRAMMER_MAP:
                if v == vid and p == pid and prog not in seen:
                    if prog in _SERIAL_PROGRAMMER_PARAMS:
                        key = _SERIAL_PROGRAMMER_PARAMS[prog]
                        port = _find_serial_port()
                        if port:
                            full_prog = f"{prog}:{key}={port}"
                            results.append((full_prog, f"{label}  [{vid}:{pid}] → {port}"))
                        else:
                            results.append((prog, f"{label}  [{vid}:{pid}] (no serial port found)"))
                    else:
                        results.append((prog, f"{label}  [{vid}:{pid}]"))
                    seen.add(prog)
    except (FileNotFoundError, OSError):
        pass

    return results


def _detect_chips(
    binary: str, programmer: str, out_queue: queue.Queue[str] | None = None
) -> tuple[list[str], str | None]:
    """Probe for chips. Returns (chips, suggested_programmer_or_None)."""
    cmd = [binary, "-p", programmer]
    if out_queue is not None:
        out_queue.put(f"$ {' '.join(cmd)}")
    try:
        proc = subprocess.run(
            cmd, check=False, capture_output=True, text=True, errors="replace", timeout=30
        )
        combined = (proc.stdout or "") + "\n" + (proc.stderr or "")
        if out_queue is not None:
            for ln in combined.splitlines():
                out_queue.put(ln)
        chips: list[str] = []
        seen: set[str] = set()
        suggested: str | None = None
        for line in combined.splitlines():
            lo = line.lower()
            # "Found GigaDevice flash chip \"GD25Q32(B)\" ..."
            # "Multiple flash chip definitions match ... \"A\", \"B\""
            if "found" in lo or "multiple" in lo or "match" in lo:
                for m in re.finditer(r'"([^"]+)"|\'([^\']+)\'', line):
                    name = m.group(1) or m.group(2)
                    if name not in seen:
                        chips.append(name)
                        seen.add(name)
            # flashrom hint: "Use flashrom -p buspirate_spi:dev=/dev/ttyUSB0"
            if not suggested:
                hint = re.search(r'Use \S+ -p (\S+)', line)
                if hint:
                    suggested = hint.group(1)
        return chips, suggested
    except Exception:
        return [], None


def _get_chip_size(binary: str, programmer: str, chip: str) -> int | None:
    try:
        proc = subprocess.run(
            [binary, "-p", programmer, "-c", chip, "--flash-size"],
            check=False, capture_output=True, text=True, errors="replace", timeout=15
        )
        lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines()
        # The size is a bare integer line; scan in reverse to skip trailing messages
        for line in reversed(lines):
            stripped = line.strip()
            if re.fullmatch(r"\d+", stripped):
                return int(stripped)
        return None
    except Exception:
        return None


def _run_command(cmd: list[str], out_queue: queue.Queue[str]) -> int:
    """Run *cmd*, echo its command line, stream output to *out_queue*. Returns exit code."""
    out_queue.put(f"$ {' '.join(cmd)}")
    try:
        proc = subprocess.Popen(
            cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
            text=True, universal_newlines=True, errors="replace",
        )
        _register_proc(proc)
        if proc.stdout is None:
            out_queue.put("ERROR: Failed to capture command output stream.")
            return 1
        for line in proc.stdout:
            if _APP_SHUTTING_DOWN.is_set() and proc.poll() is None:
                proc.terminate()
                break
            out_queue.put(line.rstrip("\n"))
        proc.wait()
        return proc.returncode
    except (FileNotFoundError, OSError, ValueError) as exc:
        out_queue.put(f"ERROR: {exc}")
        return 1
    finally:
        try:
            _unregister_proc(proc)  # type: ignore[name-defined]
        except Exception:
            pass


def _run_command_progress(
    cmd: list[str],
    out_queue: queue.Queue[str],
    pct_callback: Callable[[int], None] | None = None,
) -> int:
    """Like *_run_command* but parses real-time progress from stdout.

    Splits the process into two threads: stderr → log queue (line-based),
    stdout → char-by-char with backspace handling → log queue + *pct_callback*.
    Returns the exit code.
    """
    _pct_re = re.compile(r"(\d{1,3})\s*%")
    try:
        proc = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            universal_newlines=True,
            errors="replace",
            bufsize=1,
        )
        _register_proc(proc)
        if proc.stdout is None or proc.stderr is None:
            out_queue.put("ERROR: Failed to capture command output streams.")
            return 1

        def _read_log(stream: object) -> None:
            for raw in stream:  # type: ignore[union-attr]
                line = raw.rstrip("\r\n")
                if line.strip():
                    out_queue.put(line)

        def _read_progress(stream: object) -> None:
            buf = ""
            last_pct = -1
            while True:
                ch = stream.read(1)  # type: ignore[union-attr]
                if not ch:
                    break
                if ch == "\b":
                    if buf:
                        buf = buf[:-1]
                elif ch == "\n":
                    line = buf.strip()
                    if line:
                        out_queue.put(line)
                    buf = ""
                else:
                    buf += ch
                    if pct_callback is not None:
                        m = _pct_re.search(buf)
                        if m:
                            pct = min(int(m.group(1)), 100)
                            if pct != last_pct:
                                last_pct = pct
                                pct_callback(pct)
                if len(buf) > 500:
                    buf = buf[-100:]

        t_out = threading.Thread(target=_read_progress, args=(proc.stdout,), daemon=True)
        t_err = threading.Thread(target=_read_log,      args=(proc.stderr,), daemon=True)
        t_out.start(); t_err.start()
        started = time.monotonic()
        while t_out.is_alive() or t_err.is_alive():
            t_out.join(timeout=0.1)
            t_err.join(timeout=0.1)
            if _APP_SHUTTING_DOWN.is_set() and proc.poll() is None:
                proc.terminate()
            if time.monotonic() - started > _COMMAND_TIMEOUT_SEC:
                out_queue.put(f"ERROR: Command timed out after {_COMMAND_TIMEOUT_SEC}s")
                if proc.poll() is None:
                    proc.terminate()
                break
        return proc.wait()
    except (FileNotFoundError, OSError, ValueError) as exc:
        out_queue.put(f"ERROR: {exc}")
        return 1
    finally:
        try:
            _unregister_proc(proc)  # type: ignore[name-defined]
        except Exception:
            pass


# ────────────────────────── helpers ────────────────────────────────────────────

def _pad_file(src: str, target_size: int, tmpdir: str) -> str:
    """Copy *src* to a temp file and pad to *target_size* with 0xFF. Return new path."""
    dst = os.path.join(tmpdir, "padded_" + os.path.basename(src))
    shutil.copy2(src, dst)
    current = os.path.getsize(dst)
    if current < target_size:
        with open(dst, "ab") as f:
            f.write(b"\xff" * (target_size - current))
    return dst


def _remove_padding(path: str) -> int:
    """Truncate trailing 0xFF bytes from *path*. Return number of bytes removed."""
    with open(path, "rb") as f:
        data = f.read()
    stripped = data.rstrip(b"\xff")
    removed = len(data) - len(stripped)
    if removed:
        with open(path, "wb") as f:
            f.write(stripped)
    return removed


def _sha256_file(path: str) -> str:
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(65536), b""):
            h.update(chunk)
    return h.hexdigest()


def _fmt_elapsed(seconds: float) -> str:
    return f"{seconds:.1f}s"


def _fmt_eta(seconds: float) -> str:
    if seconds < 0:
        seconds = 0
    total = int(round(seconds))
    m, s = divmod(total, 60)
    h, m = divmod(m, 60)
    if h:
        return f"ETA {h:d}:{m:02d}:{s:02d}"
    if m:
        return f"ETA {m:d}:{s:02d}"
    return f"ETA {s:d}s"


def _completion_label(rc: int, had_error: bool = False) -> str:
    if rc == 0:
        return "Ok"
    if had_error:
        return "Error"
    return "Fail"


def _tool_label_for_preview(tool: str) -> str:
    t = (tool or "").strip().lower()
    return t if t in {"flashrom", "flashprog", "minipro"} else "flashrom"


def _preview_read_command(tool: str) -> str:
    t = _tool_label_for_preview(tool)
    if t == "minipro":
        return "minipro -p <chip> -r output.bin"
    return f"{t} -p <programmer> -c <chip> --progress -r output.bin"


def _preview_write_command(tool: str) -> str:
    t = _tool_label_for_preview(tool)
    if t == "minipro":
        return "minipro -p <chip> -w file.bin"
    return f"{t} -p <programmer> -c <chip> --progress -w file.bin"


def _preview_verify_command(tool: str) -> str:
    t = _tool_label_for_preview(tool)
    if t == "minipro":
        return "minipro -p <chip> -y file.bin"
    return f"{t} -p <programmer> -c <chip> --progress -v file.bin"


def _preview_erase_command(tool: str) -> str:
    t = _tool_label_for_preview(tool)
    if t == "minipro":
        return "minipro -p <chip> -e"
    return f"{t} -p <programmer> -c <chip> --progress -E"


def _preview_wp_command(tool: str) -> str:
    t = _tool_label_for_preview(tool)
    if t == "minipro":
        return "minipro mode: write-protect controls unavailable"
    return f"{t} -p <programmer> -c <chip> --wp-enable"


def _preview_info_command(tool: str) -> str:
    t = _tool_label_for_preview(tool)
    if t == "minipro":
        return "minipro -p <chip> -i"
    if t == "flashprog":
        return "flashprog -p <programmer> -c <chip> --flash-name"
    return "flashrom -p <programmer> -c <chip> --wp-status"


def _render_preview_command(
    template: str,
    *,
    programmer: str = "",
    chip: str = "",
    file_path: str = "",
    output_path: str = "",
) -> str:
    rendered = template
    rendered = rendered.replace("<programmer>", programmer.strip() or "<programmer>")
    rendered = rendered.replace("<chip>", chip.strip() or "<chip>")
    rendered = rendered.replace("output.bin", output_path.strip() or "output.bin")
    rendered = rendered.replace("file.bin", file_path.strip() or "file.bin")
    return rendered


def _system_beep(frequency: int = 1000, duration_ms: int = 200) -> None:
    """Cross-platform beep for operation completion."""
    if winsound:
        try:
            winsound.Beep(frequency, duration_ms)
        except Exception:
            pass
    else:
        # Unix: bell character
        try:
            sys.stdout.write('\a')
            sys.stdout.flush()
        except Exception:
            pass


class _CollapsibleFrame(ttk.Frame):
    """Collapsible LabelFrame with ▶/▼ toggle button."""

    def __init__(self, parent: tk.Widget, text: str = "", **kwargs) -> None:
        super().__init__(parent, **kwargs)
        self.expanded = False

        # Header with toggle button
        header = ttk.Frame(self)
        header.pack(fill="x", padx=0, pady=0)

        self.toggle_btn = ttk.Button(header, text="▶", width=2, command=self.toggle)
        self.toggle_btn.pack(side="left", padx=4, pady=4)

        ttk.Label(header, text=text, font=("", 10, "bold")).pack(side="left")

        # Content frame (initially hidden)
        self.container: ttk.Frame = ttk.Frame(self)
        self.container.pack(fill="both", expand=True, padx=12, pady=(0, 8))

    def toggle(self) -> None:
        """Toggle expand/collapse state."""
        if self.expanded:
            self.container.pack_forget()
            self.toggle_btn.config(text="▶")
            self.expanded = False
        else:
            self.container.pack(fill="both", expand=True, padx=12, pady=(0, 8))
            self.toggle_btn.config(text="▼")
            self.expanded = True


