class _LogWidget(scrolledtext.ScrolledText):
    """Read-only scrolled text widget with colour-coded output."""

    def __init__(
        self,
        parent: tk.Widget,
        line_sink: Callable[[str], None] | None = None,
        **kw: object,
    ) -> None:
        super().__init__(parent, state="disabled", wrap="word",
                         bg="#1e1e1e", fg="#d4d4d4",
                         font=_pick_mono(10), **kw)
        self._line_sink = line_sink
        self._verbose = True
        self.tag_config("err", foreground="#f44747")
        self.tag_config("ok",  foreground="#6a9955")
        self.tag_config("hdr", foreground="#569cd6")
        self.tag_config("cmd", foreground="#c586c0")
        self.tag_config("warn", foreground="#d7ba7d")
        self.tag_config("info", foreground="#9cdcfe")
        self.tag_config("meta", foreground="#4ec9b0")
        self.tag_config("eta", foreground="#ffd166")
        self.tag_config("sha", foreground="#b5cea8")
        self.tag_config("done", foreground="#89d185")

    def set_palette(self, dark: bool) -> None:
        if dark:
            self.configure(bg="#1e1e1e", fg="#d4d4d4", insertbackground="#d4d4d4")
            self.tag_config("err", foreground="#ff6b6b")
            self.tag_config("ok", foreground="#7fd18b")
            self.tag_config("hdr", foreground="#7fb3ff")
            self.tag_config("cmd", foreground="#d7aefb")
            self.tag_config("warn", foreground="#f2cc8f")
            self.tag_config("info", foreground="#8bd3ff")
            self.tag_config("meta", foreground="#5dd6c3")
            self.tag_config("eta", foreground="#ffd166")
            self.tag_config("sha", foreground="#c5e1a5")
            self.tag_config("done", foreground="#9ae6b4")
        else:
            self.configure(bg="#ffffff", fg="#1f2937", insertbackground="#111827")
            self.tag_config("err", foreground="#b91c1c")
            self.tag_config("ok", foreground="#15803d")
            self.tag_config("hdr", foreground="#1d4ed8")
            self.tag_config("cmd", foreground="#7c3aed")
            self.tag_config("warn", foreground="#b45309")
            self.tag_config("info", foreground="#0369a1")
            self.tag_config("meta", foreground="#0f766e")
            self.tag_config("eta", foreground="#a16207")
            self.tag_config("sha", foreground="#166534")
            self.tag_config("done", foreground="#047857")

    def append(self, text: str) -> None:
        self.config(state="normal")
        tag = ""
        lo = text.lower()
        if text.startswith("$ "):
            tag = "cmd"
        elif lo.startswith("warning") or "warning:" in lo or "warn:" in lo:
            tag = "warn"
        elif lo.startswith("error") or "error:" in lo or "failed" in lo or "abort" in lo:
            tag = "err"
        elif lo.startswith("sha256sum:"):
            tag = "sha"
        elif lo.startswith("timetaken:") or lo.startswith("eta:"):
            tag = "eta"
        elif lo.startswith("completed:"):
            tag = "done"
        elif lo.startswith("progress") or "%" in text:
            tag = "meta"
        elif any(k in lo for k in ("done", "success", "verified", "complete")):
            tag = "ok"
        elif any(k in lo for k in ("found", "using", "select", "setting", "saved", "loaded")):
            tag = "info"
        if not self._verbose and tag in {"cmd", "meta", "info"}:
            self.config(state="disabled")
            if self._line_sink is not None:
                try:
                    self._line_sink(text)
                except Exception:
                    pass
            return
        self.insert("end", text + "\n", tag)
        self.see("end")
        self.config(state="disabled")
        if self._line_sink is not None:
            try:
                self._line_sink(text)
            except Exception:
                pass

    def clear(self) -> None:
        self.config(state="normal")
        self.delete("1.0", "end")
        self.config(state="disabled")

    def set_verbose(self, enabled: bool) -> None:
        self._verbose = bool(enabled)


class _ProgressFrame(ttk.Frame):
    """Progress bar + percentage label as a single grid-able widget."""

    def __init__(self, parent: tk.Widget, length: int = 300) -> None:
        super().__init__(parent)
        self._pct_var = tk.StringVar(value="")
        self._eta_var = tk.StringVar(value="")
        self._started_at: datetime | None = None
        self._last_eta_pct: int = 0
        self._bar = ttk.Progressbar(self, length=length, maximum=100)
        self._bar.pack(side="left", fill="x", expand=True)
        ttk.Label(self, textvariable=self._pct_var, width=5, anchor="e").pack(side="left", padx=(4, 0))
        ttk.Label(self, textvariable=self._eta_var, width=12, anchor="w").pack(side="left", padx=(6, 0))

    def begin(self) -> None:
        self._started_at = datetime.now()
        self._last_eta_pct = 0
        self._eta_var.set("ETA --")

    def pulse_start(self) -> None:
        self.begin()
        self._bar.config(mode="indeterminate")
        self._bar.start(10)
        self._pct_var.set("…")

    def stop_reset(self) -> None:
        self._bar.stop()
        self._bar.config(mode="determinate", value=0)
        self._pct_var.set("")
        self._eta_var.set("")
        self._started_at = None
        self._last_eta_pct = 0

    def set_percent(self, pct: int) -> None:
        self._bar.config(mode="determinate", value=pct)
        self._pct_var.set(f"{pct}%")
        # Recalculate ETA only every 10% to reduce overhead
        should_update_eta = (pct - self._last_eta_pct >= 10) or (pct < 10 and self._last_eta_pct > 0) or pct >= 100
        if self._started_at is not None and 0 < pct < 100 and should_update_eta:
            elapsed = (datetime.now() - self._started_at).total_seconds()
            eta = elapsed * (100 - pct) / max(pct, 1)
            self._eta_var.set(_fmt_eta(eta))
            self._last_eta_pct = pct
        elif pct >= 100:
            self._eta_var.set("ETA 0s")
            self._last_eta_pct = 100
        elif pct < 10 and self._last_eta_pct == 0:
            self._eta_var.set("ETA --")


# ────────────────────────── shared autodetect mixin ───────────────────────────

class _ChipMixin:
    """Shared chip auto-detect wiring for Read / Write / Info pages."""

    # Declared so Pylance knows the types; concrete subclasses set these in __init__
    root: tk.Tk
    state: AppState
    log: _LogWidget
    chip_var: tk.StringVar
    chip_combo: ttk.Combobox
    progress: _ProgressFrame

    def _autodetect(self) -> None:
        if not self.state.programmer:
            self.log.append("Select a programmer first.")
            return
        self.log.append("Auto-detecting chip…")
        self.progress.pulse_start()
        q: queue.Queue[str] = queue.Queue()
        log_ref = self.log
        root_ref = self.root

        def _drain() -> None:
            try:
                while True:
                    log_ref.append(q.get_nowait())
            except queue.Empty:
                pass

        def _worker() -> None:
            if _is_minipro_tool(self.state.tool, self.state.binary):
                detected, label, chips, lines, _bus = _autodetect_minipro_spi_devices(self.state.binary)
                for ln in lines[:80]:
                    q.put(ln)
                if detected and label:
                    q.put(f"Using minipro programmer: {label}")
                suggested = None
            else:
                chips, suggested = _detect_chips(self.state.binary, self.state.programmer, q)
            _safe_after(root_ref, 0, _drain)
            _safe_after(root_ref, 0, lambda: self._autodetect_done(chips, suggested))

        threading.Thread(target=_worker, daemon=False).start()

    def _autodetect_done(self, chips: list[str], suggested: str | None = None) -> None:
        self.progress.stop_reset()
        self.chip_combo["values"] = chips
        if chips:
            self.chip_var.set(chips[0])
            self.log.append(f"Found {len(chips)} chip(s): {', '.join(chips)}")
            if len(chips) > 1:
                self.log.append("WARNING: Multiple chips detected — select the correct one.")
        else:
            self.log.append("No chip detected. Check programmer connection.")
            if suggested and suggested != self.state.programmer:
                self.log.append(
                    f"HINT: flashrom suggests programmer: {suggested}\n"
                    f"      Update the Programmer field and try again."
                )


