    def _browse(self) -> None:
        p = filedialog.askopenfilename(
            initialdir=self.state.workspace_dir,
            filetypes=[("ROM/BIN", "*.rom *.bin"), ("All", "*.*")],
        )
        if p:
            self.file_var.set(p)
        self.refresh_command_preview()

    def refresh_command_preview(self) -> None:
        self.cmd_preview_var.set(
            _render_preview_command(
                _preview_write_command(self.state.tool),
                programmer=self.state.programmer,
                chip=self.chip_var.get(),
                file_path=self.file_var.get(),
            )
        )

    def _run(self) -> None:
        fp = self.file_var.get().strip()
        chip = self.chip_var.get().strip()
        if not fp or not os.path.isfile(fp):
            self.log.append("ERROR: Select a valid ROM file.")
            return
        if not chip:
            self.log.append("ERROR: Run Auto Detect first.")
            return
        if not self.state.programmer:
            self.log.append("ERROR: Select a programmer first.")
            return

        if not messagebox.askyesno(
            "Confirm Write",
            "Are you sure you want to write this ROM?\n"
            "This CANNOT be undone.\n\nIt is strongly recommended to back up first!",
            icon="warning",
        ):
            return

        actual_fp = fp
        if self.opt_pad.get():
            size = _get_chip_size(self.state.binary, self.state.programmer, chip)
            if size:
                actual_fp = _pad_file(fp, size, self.state.tmpdir)
                self.log.append(f"Padded file to {size} bytes.")
            else:
                self.log.append("WARNING: Could not determine chip size — skipping padding.")

        is_minipro = _is_minipro_tool(self.state.tool, self.state.binary)
        if is_minipro:
            cmd = [self.state.binary, "-p", chip, "-w", actual_fp]
        else:
            cmd = [self.state.binary, "-p", self.state.programmer, "-c", chip, "--progress", "-w", actual_fp]
        if not is_minipro and self.opt_noverify.get():
            cmd.append("-n")

        self.log.append(f"$ {' '.join(cmd)}")
        self.progress.stop_reset()
        self.sha256_var.set("—")
        self.elapsed_var.set("—")
        self.completed_var.set("—")
        started = datetime.now()

        def _worker() -> None:
            q: queue.Queue[str] = queue.Queue()
            root_ref = self.root
            prog_ref = self.progress
            log_ref  = self.log
            had_error = [False]
            done = [False]
            digest = "N/A"
            file_exists = False

            def _drain() -> None:
                while not q.empty():
                    line = q.get_nowait()
                    if "error" in line.lower() or "failed" in line.lower():
                        had_error[0] = True
                    log_ref.append(line)
                if (not done[0]) or (not q.empty()):
                    _safe_after(root_ref, 100, _drain)

            def _pct(pct: int) -> None:
                _safe_after(root_ref, 0, lambda p=pct: prog_ref.set_percent(p))

            rc = _run_command_progress(cmd, q, pct_callback=_pct)
            done[0] = True
            file_exists = os.path.isfile(actual_fp)
            if file_exists:
                try:
                    digest = _sha256_file(actual_fp)
                except Exception as exc:
                    had_error[0] = True
                    _safe_after(root_ref, 0, lambda e=exc: log_ref.append(f"ERROR: post-write hashing failed: {e}"))

            def _done() -> None:
                _drain()
                prog_ref.stop_reset()
                elapsed = (datetime.now() - started).total_seconds()
                self.elapsed_var.set(_fmt_elapsed(elapsed))
                if file_exists:
                    self.sha256_var.set(digest)
                    log_ref.append(f"SHA256SUM: {digest}")
                else:
                    self.sha256_var.set("N/A")
                    had_error[0] = True
                log_ref.append(f"TimeTaken: {_fmt_elapsed(elapsed)}")
                status = _completion_label(rc, had_error=had_error[0])
                self.completed_var.set(status)
                log_ref.append(f"Completed: {status}")
                if rc != 0:
                    log_ref.append(f"Write failed (exit {rc}).")
                if self.state.beep_on_complete:
                    _system_beep(1000 if rc == 0 else 800, 200)

            _safe_after(root_ref, 300, _done)

        threading.Thread(target=_worker, daemon=False).start()


