    def refresh_command_preview(self) -> None:
        self.cmd_preview_var.set(
            _render_preview_command(
                _preview_info_command(self.state.tool),
                programmer=self.state.programmer,
                chip=self.chip_var.get(),
            )
        )

    def _read_info(self) -> None:
        chip = self.chip_var.get().strip()
        if not chip:
            self.log.append("ERROR: Run Auto Detect first.")
            return
        if not self.state.programmer:
            self.log.append("ERROR: Select a programmer first.")
            return
        self.progress.pulse_start()

        def _parse_chip_info(lines: list[str]) -> tuple[str, str, str]:
            """Extract (vendor, model, size_str) from flashrom/flashprog output lines."""
            vendor, model, size_str = "", "", "N/A"
            for line in lines:
                m = re.search(r'vendor="([^"]+)".*?name="([^"]+)"', line)
                if m:
                    vendor, model = m.group(1), m.group(2)
                m2 = re.search(r'Found\s+(\S+)\s+flash(?:\s+chip)?\s+"([^"]+)"', line)
                if m2 and not vendor:
                    vendor, model = m2.group(1), m2.group(2)
                if size_str == "N/A":
                    ms = re.search(r'\((\d+)\s+kB[,\s\)]', line)
                    if ms:
                        size_str = f"{ms.group(1)} kB"
                    else:
                        ms2 = re.search(r'\((\d+)\s+MB[,\s\)]', line)
                        if ms2:
                            size_str = f"{ms2.group(1)} MB"
            return vendor, model, size_str

        def _worker() -> None:
            binary = self.state.binary
            programmer = self.state.programmer
            tool = self.state.tool
            vendor = "N/A"
            model = "N/A"
            size_str = "N/A"
            chip_id_text = "N/A"
            wp = "N/A"
            probe_ids: list[tuple[int, int]] = []

            try:
                if _is_minipro_tool(tool, binary):
                    try:
                        proc = subprocess.run(
                            [binary, "-p", chip, "-i"],
                            check=False,
                            capture_output=True,
                            text=True,
                            errors="replace",
                            timeout=60,
                        )
                        out_lines = ((proc.stdout or "") + (proc.stderr or "")).splitlines()
                    except subprocess.TimeoutExpired:
                        out_lines = []

                    model, vendor, size_str = _parse_minipro_device_info(out_lines, chip)
                    chip_id_text = _extract_chip_id_from_lines(out_lines)
                    probe_ids = _extract_probe_ids_from_lines(out_lines)
                    wp = "N/A"
                elif tool != "flashprog":
                    # ── flashrom: single call to --wp-status gives Found line + WP ──
                    try:
                        proc = subprocess.run(
                            [binary, "-p", programmer, "-c", chip, "--wp-status"],
                            check=False, capture_output=True, text=True, errors="replace", timeout=60
                        )
                        out_lines = ((proc.stdout or "") + (proc.stderr or "")).splitlines()
                    except subprocess.TimeoutExpired:
                        out_lines = []

                    vendor, model, size_str = _parse_chip_info(out_lines)
                    probe_ids = _extract_probe_ids_from_lines(out_lines)
                    chip_id_match = re.search(
                        r"\bid(?:1|2)?\s*=\s*(0x[0-9a-fA-F]+|[0-9a-fA-F]{2,8})",
                        "\n".join(out_lines),
                        flags=re.IGNORECASE,
                    )
                    if chip_id_match:
                        chip_id_text = chip_id_match.group(1)

                    wp_lines = [
                        ln for ln in out_lines
                        if ln.strip()
                        and not ln.startswith("flashrom")
                        and "free software" not in ln
                        and "Using clock_gettime" not in ln
                        and "Found" not in ln
                    ]
                    wp = "\n".join(wp_lines).strip() if wp_lines else "N/A"
                else:
                    # ── flashprog: --flash-name only; no WP support in this version ─
                    try:
                        proc = subprocess.run(
                            [binary, "-p", programmer, "-c", chip, "--flash-name"],
                            check=False, capture_output=True, text=True, errors="replace", timeout=30
                        )
                        out_lines = ((proc.stdout or "") + (proc.stderr or "")).splitlines()
                    except subprocess.TimeoutExpired:
                        out_lines = []

                    vendor, model, size_str = _parse_chip_info(out_lines)
                    probe_ids = _extract_probe_ids_from_lines(out_lines)
                    chip_id_match = re.search(
                        r"\bid(?:1|2)?\s*=\s*(0x[0-9a-fA-F]+|[0-9a-fA-F]{2,8})",
                        "\n".join(out_lines),
                        flags=re.IGNORECASE,
                    )
                    if chip_id_match:
                        chip_id_text = chip_id_match.group(1)
                    wp = "N/A"
            except Exception as exc:
                _safe_after(self.root, 0, lambda e=exc: self.log.append(f"ERROR: Failed to read chip info: {e}"))

            _safe_after(self.root, 0, lambda: self._fill_info(model, vendor, size_str, chip_id_text, wp, probe_ids))

        threading.Thread(target=_worker, daemon=False).start()

    def _fill_info(
        self,
        model: str,
        vendor: str,
        size: str,
        chip_id: str,
        wp: str,
        probe_ids: list[tuple[int, int]] | None = None,
    ) -> None:
        self.progress.stop_reset()
        self._last_model = model or ""
        self._last_vendor = vendor or ""
        self._last_probe_ids = list(probe_ids or [])
        values = [model, vendor, size, chip_id, wp]
        for i, item in enumerate(self.tree.get_children()):
            self.tree.item(item, values=(values[i],))

    def _open_datasheet(self) -> None:
        chip = (self.chip_var.get() or "").strip()
        if not chip:
            self.log.append("ERROR: Select/detect a chip first.")
            return

        model = (self._last_model or chip).strip()
        vendor = (self._last_vendor or "").strip()
        target, candidates = _resolve_datasheet_target(
            chip,
            model,
            vendor,
            self._last_probe_ids,
        )
        if not target:
            self.log.append("ERROR: Could not resolve a datasheet target.")
            return

        try:
            _open_datasheet_target(target)
            self.log.append(f"Opened datasheet target: {target}")
            if candidates:
                self.log.append(f"Datasheet candidates: {', '.join(candidates[:5])}")
        except Exception as exc:
            self.log.append(f"ERROR: Failed to open datasheet target: {exc}")


