    def _run_background(
        self,
        title: str,
        worker: Callable[[], None],
        on_done: Callable[[], None] | None = None,
    ) -> None:
        def _entry() -> None:
            try:
                worker()
            except Exception as exc:
                _safe_after(
                    self.app.root,
                    0,
                    lambda e=exc, t=title: self.app.log.append(f"ERROR: {t}: {e}"),
                )
            finally:
                if on_done is not None:
                    _safe_after(self.app.root, 0, on_done)

        threading.Thread(target=_entry, daemon=False).start()

    def _browse_font(self) -> None:
        """Browse for a font file (optional UI enhancement)."""
        p = filedialog.askopenfilename(
            title="Select font file",
            filetypes=[("Font files", "*.ttf *.otf"), ("All", "*.*")],
            initialdir=self.state.workspace_dir,
        )
        if p:
            self.app.log.append(f"Selected font file: {p}")

    def _download_font(self) -> None:
        """Download a Nerd Font."""
        if not _FONT_DOWNLOADS:
            messagebox.showinfo("Download", "No fonts available for download.", parent=self.frame)
            return
        font_name = self.font_var.get()
        if font_name not in _FONT_DOWNLOADS:
            messagebox.showinfo("Download", f"No download available for '{font_name}'.", parent=self.frame)
            return

        self.btn_download_font.config(state="disabled")
        self.app.log.append(f"Downloading {font_name}...")
        result: dict[str, object] = {"ok": False, "error": None}

        def _worker() -> None:
            try:
                _download_font(font_name)
                result["ok"] = True
            except Exception as exc:
                result["error"] = exc

        def _done() -> None:
            self.btn_download_font.config(state="normal")
            if result["ok"]:
                self.app.log.append(f"Downloaded font: {font_name}")
                self.app._apply_gui_font(font_name, self.state.font_size, allow_download=True)
                messagebox.showinfo("Downloaded", f"{font_name} font downloaded.", parent=self.frame)
            else:
                err = result["error"]
                messagebox.showerror("Download failed", str(err) if err else "unknown error", parent=self.frame)

        self._run_background("font download", _worker, _done)

    def _apply_font_size(self) -> None:
        """Apply font size change immediately."""
        try:
            size = self.font_size_var.get()
            self.state.font_size = max(8, min(16, size))
            if self.state.preferred_font:
                applied = self.app._apply_gui_font(
                    self.state.preferred_font,
                    self.state.font_size,
                    allow_download=False,
                )
                if not applied:
                    self.app.log.append(
                        f"WARNING: Font '{self.state.preferred_font}' is not available; size updated for fallback font."
                    )
            self.app.log.append(f"Font size applied: {self.state.font_size}pt")
        except Exception as e:
            self.app.log.append(f"Error applying font size: {e}")

    def _preview_theme(self) -> None:
        """Preview the selected theme without applying it."""
        theme_name = self.theme_var.get().strip()
        if not theme_name:
            return
        resolved = _resolve_theme_name(self.app.style, theme_name)
        if not resolved:
            self.app.log.append(f"Error previewing theme: {theme_name} (not available)")
            return
        try:
            self.app.style.theme_use(resolved)
            self.app._apply_theme_visuals(theme_name)
            if resolved != theme_name:
                self.app.log.append(f"Theme preview: {theme_name} → {resolved} (not yet saved)")
            else:
                self.app.log.append(f"Theme preview: {theme_name} (not yet saved)")
        except tk.TclError:
            self.app.log.append(f"Error previewing theme: {theme_name}")

    def _revert_theme(self) -> None:
        """Revert to the original theme."""
        try:
            self.theme_var.set(self.theme_original)
            self.app.style.theme_use(self.theme_original)
            self.app._apply_theme_visuals(self.theme_original)
            self.app.log.append(f"Theme reverted to: {self.theme_original}")
        except tk.TclError:
            self.app.log.append(f"Error reverting theme")

    def _default_theme(self) -> None:
        """Reset to default theme."""
        themes = sorted(self.app.style.theme_names())
        if themes:
            default = themes[0]
            self.theme_var.set(default)
            self.app.style.theme_use(default)
            self.app._apply_theme_visuals(default)
            self.app.log.append(f"Theme reset to default: {default}")

    def _apply_theme(self) -> None:
        """Apply and save the selected theme."""
        theme_name = self.theme_var.get().strip()
        if not theme_name:
            return
        try:
            resolved = _resolve_theme_name(self.app.style, theme_name)
            if not resolved:
                self.app.log.append(f"ERROR: Theme '{theme_name}' is not available.")
                return
            # Apply resolved Tk theme, keep user-facing theme name in settings.
            self.app.style.theme_use(resolved)
            self.state.theme = theme_name
            self.theme_original = theme_name
            self.app._apply_theme_visuals(theme_name)
            # Persist to disk
            self.state.save_settings(geometry=self.state.window_geometry or self.app.root.geometry())
            if resolved != theme_name:
                self.app.log.append(f"Theme applied and saved: {theme_name} (mapped to {resolved})")
            else:
                self.app.log.append(f"Theme applied and saved: {theme_name}")
        except Exception as e:
            self.app.log.append(f"ERROR: Failed to apply theme '{theme_name}': {e}")

    # ── System checks & fixes ────────────────────────────────────────────────

    def _has_missing_core_binaries(self) -> bool:
        checks = [
            (self.flashrom_var.get().strip(), "flashrom"),
            (self.flashprog_var.get().strip(), "flashprog"),
            (str(getattr(self.state, "minipro_bin", "") or "").strip(), "minipro"),
            (str(getattr(self.state, "fwinfo_bin", "") or "").strip(), "fwinfo"),
        ]
        for configured, fallback in checks:
            if configured:
                if not os.path.isfile(configured):
                    return True
            else:
                if shutil.which(fallback) is None:
                    return True
        return False

    def _refresh_system_fix_buttons(self) -> None:
        should_enable_fix_dep = self._has_missing_core_binaries()
        self.btn_fix_dep.config(state="normal" if should_enable_fix_dep else "disabled")
        is_windows = sys.platform.startswith("win")
        is_linux = sys.platform.startswith("linux")
        self.btn_check_perms.config(state="disabled" if is_windows else "normal")
        self.btn_fix_perms.config(state="disabled" if is_windows else "normal")
        self.btn_check_udev.config(state="normal" if is_linux else "disabled")
        self.btn_fix_udev.config(state="normal" if is_linux else "disabled")
        self.btn_backup_udev.config(state="normal" if is_linux else "disabled")
        self.btn_add_plugdev.config(state="normal" if is_linux else "disabled")
        self.btn_reload_udev.config(state="normal" if is_linux else "disabled")
        self.btn_install_guide.config(state="normal")
        if hasattr(self, "udev_group_hint_var"):
            if is_linux:
                self.udev_group_hint_var.set(_udev_group_hint_text())
            elif sys.platform == "darwin":
                self.udev_group_hint_var.set(f"Linux-only action. {_udev_group_hint_text()}")
            else:
                self.udev_group_hint_var.set("")

    def _fix_dependencies(self) -> None:
        """Attempt to fix dependencies with safe, user-confirmed actions."""
        log = self.app.log
        log.append("=== Fix dependencies ===")

        missing_tools: list[str] = []
        for tool, configured in (
            ("flashrom", self.flashrom_var.get().strip()),
            ("flashprog", self.flashprog_var.get().strip()),
            ("minipro", str(getattr(self.state, "minipro_bin", "") or "").strip()),
            ("fwinfo", str(getattr(self.state, "fwinfo_bin", "") or "").strip()),
        ):
            found = configured if configured and os.path.isfile(configured) else shutil.which(tool)
            if not found:
                missing_tools.append(tool)

        if missing_tools:
            log.append(f"  Missing tools: {', '.join(missing_tools)}")
            if sys.platform.startswith("linux"):
                log.append("  Install hint (Debian/Ubuntu): sudo apt update && sudo apt install flashrom")
            elif sys.platform == "darwin":
                log.append("  Install hint (macOS): brew install flashrom")
            elif sys.platform.startswith("win"):
                log.append("  Install hint (Windows): use official flashrom/flashprog builds and set binary paths.")
            else:
                log.append("  Install hint: use your platform package manager, then set binary paths in Settings.")
        else:
            log.append("  flashrom/flashprog binaries are available.")

        # Optional safe fix: install keyring for secure sudo password persistence.
        should_install_keyring = False
        try:
            import keyring  # type: ignore[import]
            _ = keyring  # keep linter happy
            log.append("  keyring is already installed.")
        except ImportError:
            if shutil.which("pip"):
                should_install_keyring = messagebox.askyesno(
                    "Install keyring",
                    "The 'keyring' package is not installed.\n\n"
                    "Install it now with pip --user?",
                    parent=self.frame,
                )
                if not should_install_keyring:
                    log.append("  keyring installation skipped by user.")
            else:
                log.append("  pip not found; install keyring manually: python -m pip install --user keyring")

        if not should_install_keyring:
            log.append("=== end ===")
            return

        result: dict[str, object] = {"ok": False, "err": ""}
        log.append("  Installing keyring in background...")

        def _worker() -> None:
            try:
                proc = subprocess.run(
                    [sys.executable, "-m", "pip", "install", "--user", "keyring"],
                    check=False,
                    capture_output=True,
                    text=True,
                    errors="replace",
                    timeout=180,
                )
                if proc.returncode == 0:
                    result["ok"] = True
                else:
                    result["err"] = (proc.stderr or proc.stdout or "unknown error").strip()[:300]
            except Exception as exc:
                result["err"] = str(exc)

        def _done() -> None:
            if result["ok"]:
                log.append("  Installed keyring successfully.")
            else:
                log.append(f"  Failed to install keyring: {result['err']}")
            log.append("=== end ===")

        self._run_background("fix dependencies", _worker, _done)

    def _download_binaries(self) -> None:
        """Show platform-specific install guidance for flashrom/flashprog binaries."""
        log = self.app.log
        log.append("=== Binary install guidance ===")
        log.append("  Automatic binary downloads are intentionally disabled for safety.")
        log.append("  Install manually, then set paths in Settings:")
        if sys.platform.startswith("linux"):
            log.append("    Debian/Ubuntu: sudo apt update && sudo apt install flashrom")
            log.append("    Arch: sudo pacman -S flashrom")
            log.append("    Fedora: sudo dnf install flashrom")
        elif sys.platform == "darwin":
            log.append("    macOS: brew install flashrom")
        elif sys.platform.startswith("win"):
            log.append("    Windows: use official builds for flashrom/flashprog, then Browse to the executable.")
        else:
            log.append("    Use your OS package manager to install flashrom/flashprog.")
        log.append("=== end ===")

    def _fix_udev(self) -> None:
        """Fix udev rules (alias for _check_udev which already does fixing)."""
        self._check_udev()

    def _backup_udev(self) -> None:
        """Backup current udev rules."""
        log = self.app.log
        log.append("=== Backup udev rules ===")
        
        prog_full = self.app.state.programmer
        prog_key  = prog_full.split(":")[0] if prog_full else ""
        
        if not prog_key or prog_key not in _UDEV_RULES:
            log.append("  No programmer selected or no rules available")
            log.append("=== end ===")
            return
        
        rule_file, _ = _UDEV_RULES[prog_key]
        rule_path = f"/etc/udev/rules.d/{rule_file}"
        backup_path = f"{rule_path}.backup"
        
        if not os.path.isfile(rule_path):
            log.append(f"  {rule_path} not found — nothing to backup")
        else:
            try:
                shutil.copy(rule_path, backup_path)
                log.append(f"  ✓ Backed up to {backup_path}")
            except Exception as e:
                log.append(f"  ✗ Backup failed: {e}")
        log.append("=== end ===")

